class Solution:
    def getLengthOfOptimalCompression(self, s, k):
        import itertools
        n = len(s)
        def rle_len(t):
            if not t:
                return 0
            length = 0
            i = 0
            while i < len(t):
                j = i
                while j < len(t) and t[j] == t[i]:
                    j += 1
                cnt = j - i
                length += 1 + (0 if cnt == 1 else len(str(cnt)))
                i = j
            return length
        best = float('inf')
        idxs = list(range(n))
        for d in range(0, min(k, n) + 1):
            for combo in itertools.combinations(idxs, d):
                remove = set(combo)
                remaining = ''.join(ch for i, ch in enumerate(s) if i not in remove)
                best = min(best, rle_len(remaining))
        return best

