var getLengthOfOptimalCompression = function(s, k) {
    const n = s.length;
    const memo = new Map();
    const calcLen = (cnt) => {
        if (cnt === 0) return 0;
        if (cnt === 1) return 1;
        if (cnt < 10) return 2;
        if (cnt < 100) return 3;
        return 4;
    };
    const dp = (i, k) => {
        if (k < 0) return Infinity;
        if (n - i <= k) return 0;
        const key = i + ',' + k;
        if (memo.has(key)) return memo.get(key);
        let best = dp(i + 1, k - 1);
        let cnt = 0, deleted = 0;
        for (let j = i; j < n; j++) {
            if (s[j] === s[i]) {
                cnt++;
            } else {
                deleted++;
                if (deleted > k) break;
            }
            best = Math.min(best, calcLen(cnt) + dp(j + 1, k - deleted));
        }
        memo.set(key, best);
        return best;
    };
    return dp(0, k);
};
